mapper.update:
UPDATE NEWS
SET title          = #{title},
    stock_code     = #{stockCode},
    news_url       = #{newsUrl},
    published_date = #{publishedDate}
WHERE news_id = #{newsId}

mapper.select:
SELECT DISTINCT n.news_id, n.title, n.stock_code, n.news_url, n.published_date, n.name
FROM NEWS n
LEFT JOIN STOCK s ON s.stock_code = #{stockCode}
WHERE n.stock_code = #{stockCode}
   OR (s.stock_name IS NOT NULL
       AND s.stock_name != ''
       AND n.title LIKE CONCAT('%', s.stock_name, '%'))
ORDER BY n.published_date DESC
LIMIT #{limit}

SELECT DISTINCT n.news_id, n.title, n.stock_code, n.news_url, n.published_date, n.name
FROM NEWS n
LEFT JOIN STOCK s ON s.stock_code = #{stockCode}
WHERE n.stock_code = #{stockCode}
   OR (s.stock_name IS NOT NULL
       AND s.stock_name != ''
       AND n.title LIKE CONCAT('%', s.stock_name, '%'))
ORDER BY n.published_date DESC
LIMIT #{limit}

SELECT n.news_id, n.title, n.stock_code, n.news_url, n.published_date, n.name
FROM NEWS n
LEFT JOIN STOCK s ON n.stock_code = s.stock_code
WHERE s.country = #{country}
ORDER BY n.published_date DESC
LIMIT #{limit}

SELECT news_id, title, stock_code, news_url, published_date, name
FROM NEWS
WHERE name = #{category}
ORDER BY published_date DESC
LIMIT #{limit}

SELECT CASE WHEN COUNT(*) > 0 THEN TRUE ELSE FALSE END
FROM NEWS
WHERE news_url = #{url}

SELECT COUNT(*)
FROM NEWS
WHERE news_url = #{link}
